import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { CheckCircle, Cancel } from '@mui/icons-material';
import response from './response.json';

interface Habit {
  name: string;
  completed: boolean;
  streak: number;
}

interface HabitData {
  date: string;
  habits: Habit[];
}

export default function Widget() {
  const habitData = response.data as HabitData;
  const { date, habits } = habitData;
  const theme = response.meta.theme;
  const primaryColor = response.meta.primaryColor;
  const accentColor = response.meta.accentColor;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: theme === 'dark' ? '#1E1E1E' : '#FFFFFF',
        color: theme === 'dark' ? '#FFFFFF' : '#000000',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: accentColor }}>
              Habit Tracker
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {date}
            </Typography>
          </Box>

          <Stack spacing={1.5}>
            {habits.map((habit) => (
              <Box key={habit.name} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <Stack direction="row" alignItems="center" spacing={1}>
                  {habit.completed ? (
                    <CheckCircle sx={{ color: primaryColor }} />
                  ) : (
                    <Cancel sx={{ color: '#EF4444' }} />
                  )}
                  <Typography variant="body1" fontWeight={500}>
                    {habit.name}
                  </Typography>
                </Stack>
                <Chip
                  label={`Streak: ${habit.streak}`}
                  sx={{
                    bgcolor: primaryColor,
                    color: '#FFFFFF',
                    fontSize: '11px',
                    px: 1,
                  }}
                />
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
